toolInput.sketch:
// 7-Segment Counter — 0 to 9, button increments, wraps back to 0
// Common-cathode display
// Segments: a=D2, b=D3, c=D4, d=D5, e=D6, f=D7, g=D8
// Button: D9 (INPUT_PULLUP)

const int SEG_A = 2;
const int SEG_B = 3;
const int SEG_C = 4;
const int SEG_D = 5;
const int SEG_E = 6;
const int SEG_F = 7;
const int SEG_G = 8;
const int BTN_PIN = 9;

int counter = 0;
int lastBtnState = HIGH;

void setSegments(int a, int b, int c, int d, int e, int f, int g) {
  digitalWrite(SEG_A, a);
  digitalWrite(SEG_B, b);
  digitalWrite(SEG_C, c);
  digitalWrite(SEG_D, d);
  digitalWrite(SEG_E, e);
  digitalWrite(SEG_F, f);
  digitalWrite(SEG_G, g);
}

void showDigit(int n) {
  // a  b  c  d  e  f  g
  if      (n == 0) { setSegments(1,1,1,1,1,1,0); }
  else if (n == 1) { setSegments(0,1,1,0,0,0,0); }
  else if (n == 2) { setSegments(1,1,0,1,1,0,1); }
  else if (n == 3) { setSegments(1,1,1,1,0,0,1); }
  else if (n == 4) { setSegments(0,1,1,0,0,1,1); }
  else if (n == 5) { setSegments(1,0,1,1,0,1,1); }
  else if (n == 6) { setSegments(1,0,1,1,1,1,1); }
  else if (n == 7) { setSegments(1,1,1,0,0,0,0); }
  else if (n == 8) { setSegments(1,1,1,1,1,1,1); }
  else if (n == 9) { setSegments(1,1,1,1,0,1,1); }
}

void setup() {
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(BTN_PIN, INPUT_PULLUP);
  showDigit(0);
}

void loop() {
  int btnState = digitalRead(BTN_PIN);

  if (btnState == LOW && lastBtnState == HIGH) {
    delay(30);
    if (digitalRead(BTN_PIN) == LOW) {
      counter = counter + 1;
      if (counter > 9) {
        counter = 0;
      }
      showDigit(counter);
    }
  }

  lastBtnState = btnState;
}

